class zar {
	private final int MAX = 6;
	private int ustYuz;

	public zar() {
		ustYuz = 1;
	}

	public void atama() {
		ustYuz = (int) (Math.random() * MAX) + 1;
	}

	public void setUstYuzu(int ustYuz) {
		if (ustYuz <= MAX && ustYuz > 0)
			this.ustYuz = ustYuz;
	}

	public int getUstYuzu() {
		return ustYuz;
	}

	public String toString() {
		String sonuc = Integer.toString(ustYuz);
		return sonuc;
	}
}

public static void main(String[] args) {
	zar zar1, zar2;
	int toplam;
	zar1 = new zar();
	zar2 = new zar();
	zar1.atama();
	zar2.atama();
	System.out.println("Zar Bir: " + zar1 + ", Zar İki: " + zar2);
	zar1.atama();
	zar2.setUstYuzu(4);
