class KesirSayi {
	private int pay, payda;

	public KesirSayi(int pay, int payda) {
		if (payda == 0) payda = 1;
		if (payda < 0) { pay *= -1; payda *= -1; }
		this.pay = pay;
		this.payda = payda;
		sadelestir();
	}

	public int getPay() { return pay; }
	public int getPayda() { return payda; }

	public KesirSayi tersi() { return new KesirSayi(payda, pay); }
	public KesirSayi topla(KesirSayi op2) {
		return new KesirSayi(pay * op2.getPayda() + op2.getPay() * payda, payda * op2.getPayda());
	}
	public KesirSayi cikar(KesirSayi op2) {
		return topla(new KesirSayi(op2.getPay() * -1, op2.getPayda()));
	}
	public KesirSayi carp(KesirSayi op2) {
		return new KesirSayi(pay * op2.getPay(), payda * op2.getPayda());
	}
	public KesirSayi bol(KesirSayi op2) { return carp(op2.tersi()); }
	public boolean esitMi(KesirSayi op2) { return pay == op2.getPay() && payda == op2.getPayda(); }

	public String toString() {
		if (pay == 0) return "0";
		if (payda == 1) return pay + "";
		return pay + "/" + payda;
	}

	private void sadelestir() {
		if (pay != 0) { int o = ebob(Math.abs(pay), payda); pay /= o; payda /= o; }
	}
	private int ebob(int a, int b) {
		while (b != 0) { int t = b; b = a % b; a = t; } return a;
	}
}

