}

interface selfDrivable {
	void destination(String d);
	void drive();
}

interface movable {
	void moveUp();
	void moveDown();
	void moveLeft();
	void moveRight();
}

class Car implements movable, selfDrivable {
	private int x, y;

	@Override public void moveUp() { y--; }
	@Override public void moveDown() { y++; }
	@Override public void moveLeft() { x--; }
	@Override public void moveRight() { x++; }
	@Override public void destination(String d) { System.out.println("Destination = " + d); }
	@Override public void drive() { System.out.println("Drive"); }
}

public static void main(String[] args) {
	Car car = new Car();
	car.destination("39.878805935007165,33.44799553728058");

	selfDrivable sdCar = new Car();
	((Car)sdCar).moveDown(); // Cast işlemi örneği
}
